paulis = []
for s in stabilizers:
    if len(s) < 161:
        s = s + "I" * (161 - len(s))
    paulis.append(stim.PauliString(s))

print(f"Number of stabilizers: {len(paulis)}")
for i, p in enumerate(paulis):
    if len(p) != 161:
        print(f"WARNING: Stabilizer {i} has length {len(p)}")

anticommuting_pairs = []
for i in range(len(paulis)):
    for j in range(i + 1, len(paulis)):
        if paulis[i].commutes(paulis[j]):
            continue
        else:
            anticommuting_pairs.append((i, j))

if anticommuting_pairs:
    print(f"Found {len(anticommuting_pairs)} anticommuting pairs:")
    for i, j in anticommuting_pairs[:10]:
        print(f"  {i} and {j}")
else:
    print("All stabilizers commute.")
